DO $$ DECLARE r RECORD; new_qual text; new_check text; alter_sql text; fixed int := 0; BEGIN FOR r IN SELECT p.polrelid::regclass::text as tbl, p.polname, p.polcmd, pg_get_expr(p.polqual, p.polrelid) as qual, pg_get_expr(p.polwithcheck, p.polrelid) as wcheck FROM pg_policy p WHERE p.polrelid::regclass::text NOT LIKE 'pg_%' AND ( (pg_get_expr(p.polqual, p.polrelid) LIKE '%auth.uid()%' AND pg_get_expr(p.polqual, p.polrelid) NOT LIKE '%(select auth.uid())%') OR (pg_get_expr(p.polwithcheck, p.polrelid) LIKE '%auth.uid()%' AND pg_get_expr(p.polwithcheck, p.polrelid) NOT LIKE '%(select auth.uid())%') ) LOOP alter_sql := format('ALTER POLICY %I ON %s', r.polname, r.tbl); IF r.qual IS NOT NULL AND r.qual LIKE '%auth.uid()%' AND r.qual NOT LIKE '%(select auth.uid())%' THEN new_qual := replace(r.qual, 'auth.uid()', '(select auth.uid())'); alter_sql := alter_sql || ' USING (' || new_qual || ')'; END IF; IF r.wcheck IS NOT NULL AND r.wcheck LIKE '%auth.uid()%' AND r.wcheck NOT LIKE '%(select auth.uid())%' THEN new_check := replace(r.wcheck, 'auth.uid()', '(select auth.uid())'); alter_sql := alter_sql || ' WITH CHECK (' || new_check || ')'; END IF; BEGIN EXECUTE alter_sql; fixed := fixed + 1; EXCEPTION WHEN OTHERS THEN RAISE WARNING 'Failed to alter policy % on %: %', r.polname, r.tbl, SQLERRM; END; END LOOP; RAISE NOTICE 'Fixed % policies', fixed; END $$;;
